// 阶段锁：当前阶段未完成则下一阶段不可解锁

function canUnlockPhase(currentPhase, checklist) {
  const order = ['seal', 'power_thermal', 'comm'];
  const idx = order.indexOf(currentPhase);
  if (idx < 0) return false;

  const phaseComplete = checklist.phases[order[idx]].allChecked;
  return phaseComplete && idx + 1 < order.length;
}
